chart.config_raw:
const ctx = document.getElementById('lifecycleChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: ['Pre-Deployment', 'Post-Deployment', 'Continuous'],
    datasets: [
      {
        label: 'Academic (n = 134)',
        data: [93.28, 2.24, 4.48],
        backgroundColor: '#4dabf7',
        borderRadius: 5,
        barPercentage: 0.7,
        categoryPercentage: 0.6
      },
      {
        label: 'Grey / Industry (n = 27)',
        data: [44.44, 14.81, 40.74],
        backgroundColor: '#f6ad55',
        borderRadius: 5,
        barPercentage: 0.7,
        categoryPercentage: 0.6
      }
    ]
  },
  options: {
    animation: false,
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          font: { family: "system-ui, -apple-system, 'Segoe UI', sans-serif", size: 12 },
          color: '#4a5568',
          usePointStyle: true,
          pointStyle: 'rectRounded'
        }
      },
      tooltip: {
        callbacks: {
          label: function(context) {
            return context.dataset.label + ': ' + context.parsed.y + '%';
          }
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 100,
        ticks: {
          callback: function(value) { return value + '%'; },
          color: '#718096',
          font: { size: 12 }
        },
        grid: { color: '#e2e8f0' }
      },
      x: {
        ticks: {
          color: '#4a5568',
          font: { size: 12 }
        },
        grid: { display: false }
      }
    }
  }
});
